import json
import pickle
from base64 import b64decode

def lambda_handler(event, context):
    # Extract the body from the event
    encoded_body = event.get('body', '')
    
    # Decode the base64 encoded body
    decoded_body = b64decode(encoded_body)
    
    # Deserialize the JSON payload using pickle
    user_actions = pickle.loads(decoded_body)
    
    # Process the user actions (example: log them)
    print("User Actions:", user_actions)
    
    # Return a success response
    return {
        'statusCode': 200,
        'body': json.dumps('Actions processed successfully')
    }